import 'package:flutter_test/flutter_test.dart';

/// Shared public smoke-test contract for generated Newton/root-finding modules.
///
/// Owns the invariant checks common to these generated module tests: module id,
/// shader asset path, non-empty presets, and metadata/id consistency. It must
/// not know about concrete Newton families or import production module classes.
void expectNewtonRootFindingModuleSmoke({
  required String moduleName,
  required dynamic module,
  required String expectedId,
  required String expectedShader,
}) {
